"use client";

import React, { useState } from 'react';
import { FadeIn, SlideUp } from '@/components/animations/MotionUtils';
import { Card, CardContent } from '@/components/global/Card';
import { Input } from '@/components/global/Input';
import { Button } from '@/components/global/Button';
import Link from 'next/link';

export default function LoginPage() {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    // Simulate API Call
    setTimeout(() => {
      setIsLoading(false);
      // In a real app, redirect to /portal/dashboard or handle error
      alert("Authentication triggered");
    }, 1500);
  };

  return (
    <div className="bg-slate-50 dark:bg-slate-950 min-h-screen py-20 mt-16 flex items-center justify-center">
      <div className="max-w-md w-full px-4 sm:px-6">
        
        <FadeIn className="text-center mb-8">
          <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 dark:text-white">
            {isLogin ? "Welcome Back" : "Create an Account"}
          </h1>
          <p className="text-slate-600 dark:text-slate-400 mt-2">
            {isLogin ? "Sign in to access your student portal." : "Register to start your journey with YP Gurukul."}
          </p>
        </FadeIn>

        <SlideUp delay={0.1}>
          <Card className="shadow-xl border-primary/10">
            <CardContent className="p-8">
              <form onSubmit={handleSubmit} className="space-y-5">
                
                {!isLogin && (
                  <FadeIn>
                    <Input label="Full Name" placeholder="John Doe" required />
                  </FadeIn>
                )}
                
                <Input type="email" label="Email Address" placeholder="you@example.com" required />
                <Input type="password" label="Password" placeholder="••••••••" required />

                {isLogin && (
                  <div className="flex justify-end">
                    <Link href="#" className="text-sm text-primary hover:underline font-medium">
                      Forgot Password?
                    </Link>
                  </div>
                )}

                <Button type="submit" size="lg" className="w-full" isLoading={isLoading}>
                  {isLogin ? "Sign In" : "Register"}
                </Button>
                
              </form>

              <div className="mt-6 text-center text-sm text-slate-600 dark:text-slate-400">
                {isLogin ? "Don't have an account?" : "Already have an account?"}{" "}
                <button 
                  onClick={() => setIsLogin(!isLogin)} 
                  className="text-primary font-semibold hover:underline bg-transparent border-none p-0 cursor-pointer"
                >
                  {isLogin ? "Sign up here" : "Log in here"}
                </button>
              </div>

            </CardContent>
          </Card>
        </SlideUp>

      </div>
    </div>
  );
}
